CREATE TRIGGER [hubspot].trgUpdateorders
ON [hubspot].[orders]
AFTER UPDATE
AS
BEGIN
    SET NOCOUNT ON;
    UPDATE
        [hubspot].[orders]
    SET
        __mj_UpdatedAt = GETUTCDATE()
    FROM
        [hubspot].[orders] AS _organicTable
    INNER JOIN
        INSERTED AS I ON
        _organicTable.[hs_object_id] = I.[hs_object_id];
END;
GO
        